function LBattleViewHud:PlayHitAction()
    local hitAction
    if self._hudPara then
        hitAction = self._hudPara.hitAction
    end
    if not hitAction then
        hitAction = self._recordHitAction
    end
    if not hitAction then return end

    ---@type LBattleViewUnit
    local tarObj = self._attachUnit
    if not tarObj or tarObj:IsDisposed() then return end

    if hitAction == LFightConst.HIT_ACT_SOUND_ONLY then
        tarObj:PlayHitSound()
    elseif hitAction == LFightConst.HIT_ACT_SOUND_AND_SKILLHIT then
        if tarObj:IsCanPlayHit() then
            tarObj:PlaySkillHitAni()
        end
        tarObj:PlayHitSound()
    elseif hitAction == LFightConst.HIT_ACT_SOUND_AND_HIT then
        if tarObj:IsCanPlayHit() then
            tarObj:PlayHitAni()
        end
        tarObj:PlayHitSound()
    end
end

