function LBattleViewHud:ShowHudNode(tipTrans, textPosX, textWidth)
    if self._hudType == LFightConst.HUD_SKILL then
        local hudFollowCom = self._hudNodeCacheItem:GetHudFollowComponent(self._hudRootTrans)
        if hudFollowCom and self._attachUiRect then
            local followPos
            local obj = self._attachUnit
            local followTrans = nil
            if obj and not obj:IsDisposed() then
                followPos = obj:GetTopNodePos()
                followTrans = obj:GetDpObject():GetDpTrans()
            end
            hudFollowCom.isWorld = false
            hudFollowCom.enabled = true

            followPos = followPos or Vector3(0,0,0)
            local uiCamera = LxUiHelper.GetUICamera()
            local sceneCamera = LxUiHelper.GetSceneCamera()
            if textWidth and textWidth > 0 and followTrans then
                local range = 0
                local screenPoint = sceneCamera:WorldToScreenPoint(followTrans.position)
                local targetWorldPoint = uiCamera:ScreenToWorldPoint(screenPoint)
                local targetLocalPoint = tipTrans.parent:InverseTransformPoint(targetWorldPoint)
                local tx = targetLocalPoint.x
                if self._isLeft then
                    range = tx - textWidth * 0.5 - textPosX
                    if range < -self._designXRange then
                        range = -self._designXRange + textWidth * 0.5 + textPosX - tx + 20
                    else
                        range = 0
                    end
                else
                    range = tx + textWidth * 0.5 + textPosX
                    if range > self._self._designXRange then
                        range = self._designXRange - textWidth * 0.5 - textPosX + tx - 20
                    else
                        range = 0
                    end
                end
                followPos.x = range
            end

            hudFollowCom:SetFollow(sceneCamera, uiCamera, self._attachUiRect ,followTrans, followPos)
        end
        self._hudFollowCom = hudFollowCom
    end
    ShowObject(self._hudNodeCacheItem.hudGameObj,true)
end

---开始下一个hud的表现
function LBattleViewHud:StepToNext()
    local oldIndex = self._curIndex
    if oldIndex >= self._maxIndex then
        self._isLast = true
        return
    end

    local idx = oldIndex + 1
    self._curIndex = idx

    local hudShowData = self._hudShowList[idx]
    local oldShowData = self._hudShowList[oldIndex]
    local hudData = hudShowData.data
    local trans = hudShowData.trans

    if idx == 1 then
        self:ShowHudNode(trans, hudShowData.textPosX, hudShowData.textWidth)
    end

    local spurtingTime = 0
    local isUnitValid = self._attachUnit and not self._attachUnit:IsDisposed()
    if isUnitValid and not self._isPlaySpurting then
        if self._player and not self._player:IsDisposed() then
            local time = self._player:ExecutePlaySpurting(self._attachUnit:GetId())
            if time and time > 0 then
                self._recordHitAction = self._hudPara.hitAction
                spurtingTime = time
                self._isPlaySpurting = true
            end
        end
    end




    local hudItem = hudShowData.hudItem
    local hudGameObj = hudItem.hudGameObj
    self._isLast = idx >= self._maxIndex
    local nextData = self._hudDataList[idx + 1]
    local nextDelay = nextData and nextData:GetDelay() or 0
    self._nextDelay = nextDelay + spurtingTime

    local pos = self:GetObjPos()
    if pos then
        self._lastWorldPos = pos
    end

    --设置节点的世界坐标
    if self._lastWorldPos then trans.position = self._lastWorldPos end

    if self._group == LFightConst.HUD_GROUP_HURT then
        --x轴在小范围内偏移，错位一下
        self:SetRandX()
        local nowPos = trans.localPosition
        local nowX = nowPos.x + self._randPosX
        if hudShowData.textPosX then
            if self._isLeft then
                local allWidth = -hudShowData.textPosX - (hudShowData.textWidth or 0)
                --判断出界
                local worldPos = trans:TransformPoint(Vector3(allWidth, 0, 0))
                local tmpPos = trans.parent:InverseTransformPoint(worldPos)
                local range = tmpPos.x
                if range < -self._designXRange then
                    nowX = nowX + self._designXRange + range + (-allWidth) / 2 + 50
                    nowX = nowX - self._randPosX
                end
            else
                --判断出界
                local worldPos = trans:TransformPoint(Vector3(hudShowData.textPosX + (hudShowData.textWidth or 0), 0, 0))
                local tmpPos = trans.parent:InverseTransformPoint(worldPos)
                local range = tmpPos.x
                if range > self._designXRange then
                    nowX = nowX + self._designXRange - range - 5
                    nowX = nowX + self._randPosX
                end
            end
        end
        nowPos.x = nowX

        if self._attachUnit then
            local gridIndex = self._attachUnit:GetIndex() or 0
            --#4069同一列相邻的飘血，高度上需要做一点错开
            if gridIndex == 4 or gridIndex == 5 or gridIndex == 6 then
                nowPos.y = nowPos.y - 25
            end
        end
        trans.localPosition = nowPos
    else
        local nowPos = trans.localPosition
        local nowX = nowPos.x
        if self._isLeft then
            local allWidth = (hudShowData.textWidth or 0) * 0.5
            --判断出界
            local range = nowX  + hudShowData.textPosX - allWidth
            if range < -self._designXRange then
                nowX = -self._designXRange  - hudShowData.textPosX + allWidth + 10
            end
        else
            local allWidth = (hudShowData.textWidth or 0) * 0.5
            --判断出界
            local range = nowX  + hudShowData.textPosX + allWidth
            if range > self._designXRange then
                nowX = self._designXRange - hudShowData.textPosX -  allWidth - 10
            end
        end
        nowPos.x = nowX
        trans.localPosition = nowPos
    end

    self._seqCom:DeleteSeq(idx)
    local seqtween = self._seqCom:CreateSeq(idx)

    seqtween:AppendInterval(spurtingTime)
    seqtween:AppendCallback(function()
        ShowObject(hudGameObj,true)
        self:PlayHitAction()
    end)
    self:CreateAnim(trans,seqtween)
    seqtween:OnComplete(function()
        self._seqCom:DeleteSeq(idx)
        self._playEndCount = self._playEndCount + 1
        self._hudShowList[idx].tween = nil
    end)
    hudShowData.tween = seqtween
    seqtween:PlayForward()
end

function LBattleViewHud:ExecuteHitAni(idx,oldIndex)
end

function LBattleViewHud:CreateAnim(trans,seqtween)
    local hudAnim = self._hudPara.animation
    if hudAnim == LFightConst.HUD_ANIM_LEFT_TO_RIGHT or hudAnim == LFightConst.HUD_ANIM_RIGHT_TO_LEFT then
        return self:CreateLtoR_or_RtoLAnim(trans, hudAnim,seqtween)
    else
        return self:CreateDefaultAnim(trans, hudAnim,seqtween)
    end
end

function LBattleViewHud:CreateDefaultAnim(trans, hudAnim,seqtween)
    if not IsValid(trans) then return end

    --初始化状态
    local canvasGroup = trans:GetComponent(typeofCanvasGroup)
    canvasGroup.alpha = 1

    local isBuffHud = self._hudType == LFightConst.HUD_BUFF
    local stayTime = isBuffHud and 0.3 or 0 -- 停留时间
    local moveY = 20

    if isBuffHud then
        --buff飘的区域高度加高，2行字左右高度
        moveY = moveY + 18
    end

    local moveTime = 0.5
    local alphaTime = 0.5 -- alpha 消失时间
    local large = Vector3(2,2,2)        -- 大
    local middle = Vector3(1.5,1.5,1.5) -- 中
    local small = Vector3(1,1,1)        -- 小
    local size = self._changeType == LFightConst.HURT_TYPE_VIOLENT_ATTACK and large or middle

    local alphaStartPos = stayTime + moveTime - alphaTime + 0.5


    --放大
    local sizeTween = trans:DOScale(size,0.1):SetEase(EaseOutCubic)
    seqtween:Append(sizeTween)

    --缩小
    local smallTween = trans:DOScale(small,0.1):SetEase(EaseOutCubic)
    seqtween:Append(smallTween)

    seqtween:AppendInterval(stayTime)

    --alpha 动画消失
    local alphaTween = canvasGroup:DOFade(0,alphaTime):SetEase(EaseInSine)

    -- Y移动动画
    local moveTween = trans:DOLocalMoveY(trans.localPosition.y + moveY,moveTime)

    seqtween:Append(moveTween)
    seqtween:Insert(alphaStartPos,alphaTween)
    return seqtween
end

function LBattleViewHud:CreateLtoR_or_RtoLAnim(trans, hudAnim,seqtween)
    if not IsValid(trans) then return end

    local nowPos = trans.localPosition

    local moveX = 15
    local offsetX = -30
    if hudAnim == LFightConst.HUD_ANIM_LEFT_TO_RIGHT then
        moveX = -moveX
        offsetX = -offsetX
    end
    nowPos.x = nowPos.x + offsetX + moveX
    trans.localPosition = nowPos

    --初始化状态
    local canvasGroup = trans:GetComponent(typeofCanvasGroup)
    canvasGroup.alpha = 1

    local stayTime = 1 -- 停留时间

    local moveTime = 0.5
    local alphaTime = 0.5 -- alpha 消失时间
    local middle = Vector3(1.5,1.5,1.5) -- 中
    local small = Vector3(1,1,1)        -- 小
    local size = middle

    local alphaStartPos = stayTime + moveTime - alphaTime + 0.5


    --放大
    local sizeTween = trans:DOScale(size,0.1):SetEase(EaseOutCubic)
    seqtween:Append(sizeTween)

    --缩小
    local smallTween = trans:DOScale(small,0.1):SetEase(EaseOutCubic)
    seqtween:Append(smallTween)

    --alpha 动画消失
    local alphaTween = canvasGroup:DOFade(0,alphaTime):SetEase(EaseInSine)

    -- Y移动动画
    local moveTween = trans:DOLocalMoveX(nowPos.x - moveX,moveTime):SetEase(EaseOutCubic)

    seqtween:Append(moveTween)
    seqtween:AppendInterval(stayTime)
    seqtween:Insert(alphaStartPos,alphaTween)
    return seqtween
end


function LBattleViewHud:Initialize(colIndex, idx, hudDataList,hudPara)
    LxNodeBase.Initialize(self)

    --挂载父节点
    self._parentTrans = self._attachCacheMgr:GetHudRootTransByColIndex(colIndex)
    self._wordRootTrans = self._attachCacheMgr:GetWordRootTrans()

    self._seqCom = require("LApp.component.tween.LxSequenceCom"):new()

    self._colIndex = colIndex
    
    self._idx = idx
    self._isStart = false

    self._hudDataList = hudDataList
    self._text = hudPara.text
    self._addOrReduceBuff = hudPara.addOrReduceBuff
    self._lastWorldPos = self:GetObjPos()
    local isLeft = hudPara.isLeft
    if isLeft ~= nil then self._isLeft = isLeft end
    local pos = hudPara.pos
    if pos then
        self._objPos = pos:Clone()
    else
        self._objPos = Vector3(0,0,0)
    end
    self._hudPara = hudPara
    self._group = LFightConst.HurtTypeGroup[hudPara.changeType] or LFightConst.HUD_GROUP_HURT

    self._randPosX = 0
end

function LBattleViewHud:SetStartTime(time)
    self._isStart = true
    self._startTime = time
end

function LBattleViewHud:InitHud()
    if self._isPlaying then return end
    self._isPlaying = true
    self:PrepareAllHud()
    self:StepToNext()
end

--初始化所有的伤害
function LBattleViewHud:PrepareAllHud()
    local hudItem = self._attachCacheMgr:GetHudItem()
    self._hudNodeCacheItem = hudItem
    local hudTrans = hudItem.hudTrans
    hudTrans.localPosition = Vector3.zero
    self._hudRootTrans = hudTrans

    ShowObject(hudItem.hudGameObj,false)

    local hudDataList = self._hudDataList
    local hudShowList = {}
    self._hudShowList = hudShowList
    local hudShowData = nil

    local bChangeParent = false
    for k,v in ipairs(hudDataList) do
        hudShowData = self:CreateHud(v)
        table.insert(hudShowList,hudShowData)
        if hudShowData.hudType == LFightConst.HUD_BUFF then
            bChangeParent = true
        end
    end

    if bChangeParent then
        hudTrans:SetParent(self._wordRootTrans,false)
        ResetTransDefault(hudTrans)
    else
        hudTrans:SetParent(self._parentTrans,false)
        ResetTransDefault(hudTrans)
    end

    self._maxIndex = #hudShowList
end

--伤害类型转成hud的类型
---@param hudData LFightHudData
function LBattleViewHud:ConvertHudType(hudData)
    local changeType = hudData:GetChangeType()
    local hudType = LBattleViewHud.HurtTypeToHudMap[changeType]
    if hudType then
        return hudType
    end
    return LFightConst.HUD_COMMON
end

function LBattleViewHud:CreateHud(hudData)
    local hudType = self:ConvertHudType(hudData)
    self._hudType = hudType

    self._changeType = hudData:GetChangeType()

    if hudType == LFightConst.HUD_TIP then
        return self:CreateTipHud(hudType, hudData)
    elseif hudType == LFightConst.HUD_BUFF then
        return self:CreateBuffHud(hudType, hudData)
    elseif hudType == LFightConst.HUD_SKILL then
        return self:CreateSkillHud(hudType, hudData)
    elseif hudType == LFightConst.HUD_TREA then
        return self:CreateTreaHud(hudType, hudData)
    else
        return self:CreateNormal(hudType, hudData)
    end
end

---@param hudData LFightHudData
function LBattleViewHud:CreateTipHud(hudType, hudData)
    local itemKey = _BuffHud_key_Map.Blue
    local hudItem = self._attachCacheMgr:GetBuffTypeUI(itemKey)
    local hudTrans = hudItem.hudTrans
    hudTrans:SetParent(self._hudRootTrans, false)
    ResetTransDefault(hudTrans)
    ShowObject(hudItem.hudGameObj,false)
    local textTrans = hudItem:FindTransWithName(hudTrans,"Content/Text")
    local cText = hudItem:GetText(textTrans)
    local textWidth = 0
    if cText then
        self:SetText(cText, self._text)
        textWidth = cText.preferredWidth
    end
    return {hudType = hudType, hudItem = hudItem, trans = hudTrans, data = hudData,tween = nil, textPosX = 0, textWidth = textWidth}
end

---@param hudData LFightHudData
function LBattleViewHud:CreateBuffHud(hudType, hudData)
    local itemKey
    local addOrReduceBuff = tonumber(self._addOrReduceBuff)
    if addOrReduceBuff == LFightConst.HUD_ICON_FAVORABLE then
        itemKey = _BuffHud_key_Map.Green
    else
        itemKey = _BuffHud_key_Map.Blue
    end
    local hudItem = self._attachCacheMgr:GetBuffTypeUI(itemKey)
    local hudTrans = hudItem.hudTrans
    hudTrans:SetParent(self._hudRootTrans, false)
    ResetTransDefault(hudTrans)
    ShowObject(hudItem.hudGameObj,false)
    local textTrans = hudItem:FindTransWithName(hudTrans,"Content/Text")
    local cText = hudItem:GetText(textTrans)
    local textWidth = 0
    if cText then
        self:SetText(cText, self._text)
        textWidth = cText.preferredWidth
    end
    return {hudType = hudType, hudItem=hudItem, trans = hudTrans, data=hudData,tween = nil,  textPosX = 0, textWidth = textWidth}
end

---@param hudData LFightHudData
function LBattleViewHud:CreateSkillHud(hudType,hudData)
    local skillId = self._hudPara.skillId
    ---@type V_SkillRef
    local skillRef = GameTable.SnakeSkillRef[skillId]
    local skillName = ""
    if skillRef then
        skillName = I18nText(skillRef.name)
    end

    local heroRace = hudData.heroRace
    local itemKey = heroRace
    local hudItem = self._attachCacheMgr:GetSkillRaceUI(itemKey)
    local hudTrans = hudItem.hudTrans
    hudTrans:SetParent(self._hudRootTrans, false)
    ResetTransDefault(hudTrans)
    ShowObject(hudItem.hudGameObj,false)

    local textTrans = hudItem:FindTransWithName(hudTrans,"Content/Text")
    local cText = hudItem:GetText(textTrans)
    local textWidth = 0
    if cText then
        self:SetText(cText, skillName)
        textWidth = cText.preferredWidth
    end
    return {hudType = hudType, hudItem=hudItem, trans = hudTrans, data=hudData,tween = nil, textPosX = 0, textWidth = textWidth}
end

---@param hudData LFightHudData
function LBattleViewHud:CreateTreaHud(hudType,hudData)
    local itemKey =  _HurtHud_key_Map.Green
    local hudItem = self._attachCacheMgr:GetHurtTypeUI(itemKey)
    local hudTrans = hudItem.hudTrans
    hudTrans:SetParent(self._hudRootTrans, false)
    ResetTransDefault(hudTrans)
    ShowObject(hudItem.hudGameObj,false)

    local skillId = self._hudPara.skillId
    ---@type V_SkillRef
    local skillRef = GameTable.SnakeSkillRef[skillId]
    local skillName = ""
    if skillRef and skillRef.nameIcon1 == 1 then
        skillName = I18nText(skillRef.name)
    end
    local textTrans = hudItem:FindTransWithName(hudTrans,"Content/Text")
    local cText = hudItem:GetText(textTrans)
    local textWidth = 0
    if cText then
        self:SetText(cText, skillName)
        textWidth = cText.preferredWidth
    end
    return {hudType = hudType, hudItem=hudItem, trans = hudTrans, data=hudData,tween = nil, textPosX = 0, textWidth = textWidth}
end

---@param hudData LFightHudData
function LBattleViewHud:CreateNormal(hudType,hudData)
    local damageName = hudData:GetDamageName() or ""
    local damageColor = hudData:GetDamageColor()
    local changeType = hudData:GetChangeType()

    local itemKey =  string.isempty(damageColor) and _HurtHud_key_Map.Blue or damageColor

    local hudItem = self._attachCacheMgr:GetHurtTypeUI(itemKey)
    if not hudItem then
        if LOG_INFO_ENABLED then
            LogError("找不到对应的飘字项目，itemKey="..tostring(itemKey))
        end
    end
    local hudTrans = hudItem.hudTrans
    hudTrans:SetParent(self._hudRootTrans, false)
    ResetTransDefault(hudTrans)
    ShowObject(hudItem.hudGameObj,false)

    local numType = hudData:GetNumType()
    local hurt = math.floor(math.abs(hudData:GetHurt()))

    local addPrefixStr = ""
    if numType == 1 then
        addPrefixStr = "+"
    elseif numType == 2 then
        addPrefixStr = "-"
    end

    local text = ""
    if hurt ~= 0 then
        text =string.format("%s%s%s", damageName, addPrefixStr,LxDataHelper.FormatNum(hurt))
    else
        if not string.isempty(damageName) then
            text = damageName
        end
    end

    if LOG_INFO_ENABLED then
        if string.isempty(text) then
            printError("battle", "飘字内容为空字符串，请检测逻辑")
        end
    end

    local textTrans = hudItem:FindTransWithName(hudTrans,"Content/Text")
    local cText = hudItem:GetText(textTrans)
    local textWidth = 0
    if cText then
        self:SetText(cText, text)
        textWidth = cText.preferredWidth
    end

    return {hudType = hudType, hudItem=hudItem, trans = hudTrans, data=hudData,tween = nil, textPosX = 0, textWidth = textWidth}
end

----获取对象当前坐标在ui坐标中的映射位置
function LBattleViewHud:GetObjPos()
    local obj = self._objPos
    if obj then
        local objPos = obj
        if not objPos then return Vector3.zero end
        local sceneCamera = LxUiHelper.GetSceneCamera()
        local uiCamera = LxUiHelper.GetUICamera()
        objPos = Vector3(objPos.x,objPos.y,0)
        --坐标轴转换：将角色位置坐标，转化为屏幕坐标。屏幕坐标转化为世界坐标，设置UI坐标。
        local screenPos  = sceneCamera:WorldToScreenPoint(objPos)
        local worldPos = uiCamera:ScreenToWorldPoint(screenPos)
        worldPos.z = 0
        return worldPos
    end
end

-----------------------------------------------------------------
function LBattleViewHud:OnUpdate(time)
    if self:IsDisposed() then return false end

    if not self._isStart then return end

    if not self._isPlaying then
        if self._startTime <= time then
            self:InitHud()
        end
    end

    if self._isPlaying then
        if self._playEndCount >= self._maxIndex then
            return false
        end
        if not self._isLast then
            if not self._nextDelay then return false end

            time = time - self._startTime
            if self._nextDelay <= time then
                self:StepToNext()
            end
        end
    end

    return true
end

function LBattleViewHud:IsValid()
    if self._attachUnit and self._attachUnit:IsDisposed() then
        return false
    end
    return true
end

function LBattleViewHud:Dispose()
    if self._isDisposed then return end

    if self._seqCom then
        self._seqCom:Dispose()
        self._seqCom = nil
    end

    local cacheMgr = self._attachCacheMgr

    if self._hudShowList then
        ---@type LBattleHudCacheItem
        local hudItem
        for _,v in ipairs(self._hudShowList) do
            v.tweenKey = nil
            v.trans = nil
            hudItem = v.hudItem
            if hudItem then
                if hudItem.itemType == 1 then
                    cacheMgr:ReturnHurtTypeUI(hudItem)
                elseif hudItem.itemType == 2 then
                    cacheMgr:ReturnBuffTypeUI(hudItem)
                elseif hudItem.itemType == 3 then
                    cacheMgr:ReturnSkillRaceUI(hudItem)
                end
            end
            v.hudItem = nil
        end
        self._hudShowList = nil
    end

    if self._hudNodeCacheItem  then
        local hudFollowCom = self._hudFollowCom
        if hudFollowCom then
            hudFollowCom.target = nil
            hudFollowCom.uiTransRoot = nil
            hudFollowCom.enabled = false
        end
        self._hudFollowCom = nil
        cacheMgr:ReturnHudItem(self._hudNodeCacheItem)
        self._hudNodeCacheItem = nil
    end

    LxNodeBase.Dispose(self)

    self._isDisposed = true
end

function LBattleViewHud:IsDisposed()
    return self._isDisposed
end

return LBattleViewHud